contributions.yaml_content:
version: 1
provider_pools:
  openrouter: { concurrency: 20, rate_limit: { max_requests: 60, window_secs: 60 } }
  ollama-local: { concurrency: 1 }
routing_rules:
  - name: default
    match_config: {}
    route_to:
      - { provider_id: market }
      - { provider_id: fleet }
      # Explicit openrouter model_id so fresh installs don't inherit an
      # Ollama format name from primary_model and trip OpenRouter's model
      # validator (post-ship C1 guard). Operator can override in Settings.
      - { provider_id: openrouter }
      - { provider_id: ollama-local, is_local: true }
    sequential: false
# escalation/wait fields retired — walker never awaits capacity (§4.5).
# max_wait_secs per-entry work-await is sourced from compute_participation_policy.market_dispatch_max_wait_ms.
